            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.5, delay: 0.2 }}
            className="bg-white rounded-lg shadow-md overflow-hidden"
          >
            <div className="px-6 py-8">
              <h3 className="text-2xl font-bold text-gray-900 mb-6">Contact Information</h3>
              <div className="space-y-6">
                <div className="flex items-start">
                  <div className="flex-shrink-0">
                    <IconWrapper icon={FaEnvelope} className="h-6 w-6 text-indigo-600" />
                  </div>
                  <div className="ml-3 text-base">
                    <p className="font-medium text-gray-900">Email</p>
                    <p className="text-gray-500">youremail@example.com</p>
                  </div>
                </div>
                <div className="flex items-start">
                  <div className="flex-shrink-0">
                    <IconWrapper icon={FaPhone} className="h-6 w-6 text-indigo-600" />
                  </div>
                  <div className="ml-3 text-base">
                    <p className="font-medium text-gray-900">Phone</p>
                    <p className="text-gray-500">+1 (555) 123-4567</p>
                  </div>
                </div>
                <div className="flex items-start">
                  <div className="flex-shrink-0">
                    <IconWrapper icon={FaMapMarkerAlt} className="h-6 w-6 text-indigo-600" />
                  </div>
                  <div className="ml-3 text-base">
                    <p className="font-medium text-gray-900">Location</p>
                    <p className="text-gray-500">San Francisco, CA</p>
                  </div>
                </div>
              </div>

              <div className="mt-10">
